form:Form.form:Scripts:
		function CusonLoad()
{
OnLoad();

//LImpio los campos
Ctrl('concepto').SetXValue('');
Ctrl('departamento').SetXValue('');
Ctrl('sujeto').SetXValue('');
Ctrl('sucursal').SetXValue('');

var nSQL = GetProxy().SQLService();	 

var param = "<DATA id=\""+Ctrl('ID').GetXValue()+"\" />"; 	 


var objShow = nSQL.GetOBJ(Ctrl("main").getResource("getDatosShow"),param);
//Asigno los campos
Ctrl('concepto').SetXValue(objShow.concepto);
Ctrl('departamento').SetXValue(objShow.departamento);
Ctrl('sujeto').SetXValue(objShow.sujeto);
Ctrl('sucursal').SetXValue(objShow.sucursal);




}
